@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-100: #eaeaea;
  --color-neutral-200: #cccccc;
  --color-neutral-400: #a0a0a0;
  --color-neutral-500: #878787;
  --color-neutral-600: #666666;
  --color-neutral-700: #4b4c57;
  --color-neutral-800: #404040;
  --color-neutral-900: #333333;
  --color-neutral-950: #1f1f1f;
  --color-red: #ef4444;
  --color-cyan: #0070f3;
  --color-orange: #ff9900;
  --color-pale-cyan: #e1f0fd;
  --color-lime: #95bf47;
  --color-pale-orange: #ffe8cc;
  --color-pink: #de2670;
  --color-indigo: #7928ca;
  --color-pink-2: #eb367f;
  --color-yellow: #febb2e;
  --color-orange-2: #bd5200;
  --color-pale-green: #d3f9d8;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #ffffff;
  --color-ink: #1f1f1f;
  --color-text-muted: #878787;
  --color-surface: #eaeaea;
  --color-hairline: #cccccc;
  --color-accent: #ef4444;
  --color-accent-2: #0070f3;
  --color-accent-3: #ff9900;

  --font-sans: "GeistSans", ui-sans-serif, system-ui, sans-serif;
  --font-serif: "Georgia", ui-serif, Georgia, serif;
  --font-mono: "Geist Mono", ui-monospace, monospace;

  --text-xs: 0.75rem;
  --text-sm: 0.8125rem;
  --text-base: 0.875rem;
  --text-lg: 1rem;
  --text-xl: 1.125rem;
  --text-2xl: 1.25rem;
  --text-3xl: 1.5rem;
  --text-4xl: 2rem;
  --text-5xl: 2.5rem;
  --text-6xl: 3rem;
  --text-7xl: 3.5rem;
  --text-8xl: 4rem;

  --font-weight-thin: 100;
  --font-weight-normal: 400;
  --font-weight-450: 450;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* line-heights, sorted tight -> loose */
  --leading-none: 0.75;
  --leading-tight: 1;
  --leading-snug: 1.05;
  --leading-normal: 1.1;
  --leading-relaxed: 1.2;
  --leading-loose: 1.3;
  --leading-looser: 1.5;
  --leading-loosest: 1.6;

  /* letter-spacing, sorted tight -> wide */
  --tracking-tightest: -2.88px;
  --tracking-tighter: -2.4px;
  --tracking-tight: -1.28px;
  --tracking-normal: -.96px;
  --tracking-wide: -.4px;
  --tracking-wider: -.32px;

  --radius-sm: 2px;
  --radius-md: .25rem;
  --radius-lg: 6px;
  --radius-xl: 8px;
  --radius-2xl: 12px;
  --radius-3xl: 100%;
  --radius-full: 50%;

  /* shadows, sorted by blur */
  --shadow-sm: 0 1px 2px #0000000a;

  --breakpoint-sm: 23.125rem;
  --breakpoint-md: 23.4375rem;
  --breakpoint-lg: 23.75rem;
  --breakpoint-xl: 23.9375rem;
  --breakpoint-2xl: 24rem;
  --breakpoint-3xl: 25rem;
  --breakpoint-4xl: 25.0625rem;
  --breakpoint-5xl: 27.5rem;

  /* most-used spacing values on the source site (px): 1, 2, 4, 8, 12, 16, 20, 24, 32, 40, 48, 64 */
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --tw-gradient-from: var(--ds-background-200);
    --tw-gradient-via: var(--ds-background-200);
    --tw-gradient-to: var(--ds-background-200);
